,-0.03266590,0.01191886,0.02899995,-0.01681330,0.02133110,0.05734687,0.00560695,0.05013694,-0.02895208,0.05967735,-0.02724986,0.10029642,-0.03799134,0.00492406,-0.07760455,-0.01193213,-0.02256353,-0.04998558,0.02907296,0.01619148,0.01143959,0.08011645,-0.05014704,-0.01021793,-0.10305110,-0.00742533,0.03885192,-0.01021455,-0.04586416,0.01148596,-0.03601921,-0.00451710,0.03137968,0.04625534,-0.02780326,-0.07563031,0.01660029,0.05121515,-0.03705695,0.14269811,-0.01196426,-0.03602118]',E'Example\n\n```go\npackage main\n\nimport (\n  "github.com/labstack/echo/v5"\n  "github.com/labstack/echo/v5/middleware"\n  "log/slog"\n  "net/http"\n)\n\nfunc main() {\n  // Echo instance\n  e := echo.New()\n\n  // Middleware\n  e.Use(middleware.RequestLogger()) // use the RequestLogger middleware with slog logger\n  e.Use(middleware.Recover())       // recover panics as errors for proper error handling\n\n  // Routes\n  e.GET("/", hello)\n\n  // Start server\n  if err := e.Start(":8080"); err != nil {\n    slog.Error("failed to start server", "error", err)\n  }\n}\n\n// Handler\nfunc hello(c *echo.Context) error {\n  return c.String(http.StatusOK, "Hello, World!")\n}\n```','{"source": "go-echo", "version": "5.1", "language": "go", "title": "Official middleware repositories", "section_title": "README", "url": "https://github.com/labstack/echo/blob/master/README.md", "topics": "echo,http,README", "categories": "web,go,rest"}');
